#!/usr/bin/env node
// Batch-patch: change every webhook trigger's responseMode from "responseNode"
// (which requires a Respond to Webhook node) to "onReceived" (fires immediately).
//
// Reason: many Zero Risk workflows were generated by research with responseMode=responseNode
// but no Respond to Webhook node, causing "No Respond to Webhook node found" 500 at fire time.
//
// Usage: node scripts/smoke-test/patch-webhook-response-mode.mjs [--dry-run]

import { endpoints } from './lib/env.mjs'
import { fetchJson } from './lib/fetch.mjs'

const ep = endpoints()
const H = { 'X-N8N-API-KEY': ep.N8N_API_KEY, 'Content-Type': 'application/json', 'Accept': 'application/json' }
const DRY = process.argv.includes('--dry-run')

const listRes = await fetchJson(ep.n8n + '/api/v1/workflows?limit=100', { headers: H })
const workflows = listRes.json?.data || []
console.log(`Scanning ${workflows.length} workflows...`)

let patched = 0, skipped = 0, failed = 0, scanned = 0
for (const w of workflows) {
  scanned++
  const detail = await fetchJson(ep.n8n + '/api/v1/workflows/' + w.id, { headers: H })
  if (!detail.ok || !detail.json?.nodes) { failed++; continue }
  const wf = detail.json
  let changed = false
  for (const n of wf.nodes) {
    if (n.type !== 'n8n-nodes-base.webhook') continue
    const mode = n.parameters?.responseMode
    // Patch "responseNode" (legacy) and undefined (some workflows leave it default which breaks)
    if (mode === 'responseNode' || mode === 'lastNode') {
      // Check if workflow has a Respond to Webhook node — if yes, keep responseNode
      const hasRespond = wf.nodes.some(nn => nn.type === 'n8n-nodes-base.respondToWebhook')
      if (hasRespond) { continue }
      n.parameters.responseMode = 'onReceived'
      changed = true
    }
  }
  if (!changed) { skipped++; continue }
  if (DRY) { console.log(`  [DRY] would patch: ${w.name}`); patched++; continue }
  const put = await fetchJson(ep.n8n + '/api/v1/workflows/' + w.id, {
    method: 'PUT', headers: H,
    body: JSON.stringify({ name: wf.name, nodes: wf.nodes, connections: wf.connections, settings: wf.settings || { executionOrder: 'v1' } }),
  })
  if (put.ok) {
    // Re-activate if it was active (PUT sometimes deactivates)
    if (w.active) {
      await fetchJson(ep.n8n + '/api/v1/workflows/' + w.id + '/deactivate', { method:'POST', headers:H, body:'{}' })
      await new Promise(r => setTimeout(r, 800))
      await fetchJson(ep.n8n + '/api/v1/workflows/' + w.id + '/activate', { method:'POST', headers:H, body:'{}' })
    }
    console.log(`  [OK] ${w.name}`)
    patched++
  } else {
    console.log(`  [FAIL ${put.status}] ${w.name}: ${put.text || put.error}`)
    failed++
  }
  await new Promise(r => setTimeout(r, 600))
}

console.log(`\nSummary: scanned=${scanned}  patched=${patched}  unchanged=${skipped}  failed=${failed}${DRY ? '  (DRY RUN — no writes)' : ''}`)
